// ── Thresholds — TUNE: document changes in docs/tuning-notes.md ──────────
let DenialThreshold    = 5;        // TUNE: MFA denial count threshold
let TimeWindowMinutes  = 10;       // TUNE: rolling window (minutes)
let LookbackWindow     = 1d;       // TUNE: search window per scheduled run
// ── Watchlist lookups ──────────────────────────────────────────────────────
let VIPList = _GetWatchlist("VIPUsers")
    | project UPN = UserPrincipalName, ObjId = ObjectId, VIPReason;
let PrivList = _GetWatchlist("PrivilegedAccounts")
    | project UPN = UserPrincipalName, ObjId = ObjectId, AssignedRole, RoleSource;
// ── Base events: MFA denied / push-declined sign-in attempts ──────────────
// ResultType 500121 = MFA required, denied or push notification declined
// ResultType 50074  = Strong auth required (user cancelled / timed out)
// ResultType 50076  = MFA challenge presented but not satisfied
let MFADenials = SigninLogs
    | where TimeGenerated > ago(LookbackWindow)
    | where ResultType in (500121, 50074, 50076)
    | project TimeGenerated, UserPrincipalName, UserId,
              IPAddress, AppDisplayName, ResultType, ResultDescription,
              ConditionalAccessStatus, AuthenticationDetails;
// ── Aggregate denials within the rolling window ────────────────────────────
let BaseEvents = MFADenials
    | summarize DenialCount    = count(),
                FirstDenial    = min(TimeGenerated),
                LastDenial     = max(TimeGenerated),
                UniqueIPs      = make_set(IPAddress, 20),
                Apps           = make_set(AppDisplayName, 10),
                ResultTypes    = make_set(ResultType, 5)
      by UserPrincipalName, UserId,
         bin(TimeGenerated, totimespan(strcat(tostring(TimeWindowMinutes), 'm')))
    | where DenialCount >= DenialThreshold;
// ── Apply watchlist joins and RiskScore boost ──────────────────────────────
BaseEvents
| join kind=leftouter (VIPList)  on $left.UserPrincipalName == $right.UPN
| join kind=leftouter (PrivList) on $left.UserPrincipalName == $right.UPN
| extend IsVIP  = isnotempty(VIPReason),
         IsPriv = isnotempty(AssignedRole)
// TUNABLE: +10 VIP-only, +10 Priv-only, +25 both (iff — not cumulative addition)
| extend RiskBoost = case(IsVIP and IsPriv, 25, IsVIP or IsPriv, 10, 0)
| extend RiskScore = RiskBoost
| extend RiskLabel = case(
    IsVIP and IsPriv, strcat(UserPrincipalName, " [VIP+PRIV — HIGHEST PRIORITY]"),
    IsVIP,            strcat(UserPrincipalName, " [VIP]"),
    IsPriv,           strcat(UserPrincipalName, " [PRIV]"),
    UserPrincipalName)
| sort by RiskScore desc, DenialCount desc, LastDenial desc
| project FirstDenial, LastDenial, RiskLabel, RiskScore,
          IsVIP, IsPriv, VIPReason, AssignedRole, RoleSource,
          DenialCount, UniqueIPs, Apps, ResultTypes,
          WindowMinutes = TimeWindowMinutes
